//! thoth-social-agent — the autonomous loop for Thoth's social organ (Phase 2).
//!
//! Composes the verified `social_presence` primitives into a live perceive →
//! drive → reason → gate → speak loop, brokered by edgework: it reads/writes the
//! edgework-gated dashrelay `POST /api/social` with Thoth's `dr_` key and asks the
//! LM (openai-server) for utterance text. Default-on with **graceful degradation**:
//! with no `THOTH_SOCIAL_DR_KEY` it idles (no posts); X reads/posts that 403
//! `client-not-enrolled` (pre-Basic) surface as `Held` with a visible reason.
//!
//! In-process: the organ logic is this crate's `social_presence` — no bridge. The
//! only IO is `ureq` to two HTTP surfaces. Mirrors `protocol69-embed-agent.rs`.
//!
//! Usage:
//!   thoth-social-agent --handle <thoth_x_handle> [--platform x] [--once]
//!                      [--interval-secs 300] [--draft-only]
//!                      [--dashrelay-url https://dashrelay.com]
//!                      [--openai-url http://localhost:8081]
//!                      [--ingest-mentions]
//!                      [--content-bus-url https://skymesh.example]
//! Env: THOTH_SOCIAL_DR_KEY=dr_…   (the edgework/dashrelay API key)

use std::time::Duration;

use distributed_inference::social_presence::{
    assemble_conscience, build_utterance_prompt, next_impulse, perceive, propose_utterance,
    rate_remaining_from_header, summarize, utterance_action_json, Autonomy, DriveWeights, Impulse,
    MouthDecision, PerceivedPost, SocialUtterance,
};
use distributed_inference::support::{build_support_reply_prompt, triage_mention};

struct Cli {
    dashrelay_url: String,
    openai_url: String,
    handle: String,
    platform: String,
    interval_secs: u64,
    once: bool,
    draft_only: bool,
    content_bus_url: String,
    content_bus_token: Option<String>,
    /// Handles whose reply-flags carry editorial weight ("flagged by editor").
    /// Everyone else's flags ride as unvetted public tips with no weight.
    editor_handles: Vec<String>,
    /// Default-ON: the editors' own likes are silent flags (no public mention
    /// needed). Disable with --no-likes-ingest or THOTH_LIKES_INGEST=false.
    likes_ingest: bool,
    /// Content-bus source mode: read mentions, convert them to contentTask
    /// offers, and stop there. The existing contentJudge leg owns judgment.
    ingest_mentions: bool,
    /// Support-desk mode: triage support mentions and answer them (gated-autonomous),
    /// instead of the general drives loop.
    support: bool,
}

fn parse_editor_handles(raw: &str) -> Vec<String> {
    raw.split(',')
        .map(|h| h.trim().trim_start_matches('@').to_ascii_lowercase())
        .filter(|h| !h.is_empty())
        .collect()
}

fn parse_cli() -> Cli {
    let content_bus_url = std::env::var("SKYMESH_CONTENT_BUS_URL")
        .or_else(|_| std::env::var("CONTENT_BUS_URL"))
        .unwrap_or_else(|_| "http://127.0.0.1:8787".into());
    let editor_handles = parse_editor_handles(
        &std::env::var("THOTH_EDITOR_HANDLES")
            .unwrap_or_else(|_| "cissypatterson,taylorbuley".into()),
    );
    let likes_ingest = !matches!(
        std::env::var("THOTH_LIKES_INGEST").as_deref(),
        Ok("false") | Ok("0")
    );
    let mut cli = Cli {
        dashrelay_url: std::env::var("DASHRELAY_URL").unwrap_or_else(|_| "https://dashrelay.com".into()),
        openai_url: std::env::var("OPENAI_URL").unwrap_or_else(|_| "http://localhost:8081".into()),
        handle: std::env::var("THOTH_SOCIAL_HANDLE").unwrap_or_default(),
        platform: "x".into(),
        interval_secs: 300,
        once: false,
        draft_only: false,
        content_bus_url,
        content_bus_token: std::env::var("THOTH_CONTENT_BUS_TOKEN").ok().filter(|s| !s.is_empty()),
        ingest_mentions: false,
        support: false,
        editor_handles,
        likes_ingest,
    };
    let mut args = std::env::args().skip(1);
    while let Some(arg) = args.next() {
        match arg.as_str() {
            "--dashrelay-url" => cli.dashrelay_url = args.next().unwrap_or(cli.dashrelay_url),
            "--openai-url" => cli.openai_url = args.next().unwrap_or(cli.openai_url),
            "--content-bus-url" => cli.content_bus_url = args.next().unwrap_or(cli.content_bus_url),
            "--handle" => cli.handle = args.next().unwrap_or_default(),
            "--platform" => cli.platform = args.next().unwrap_or(cli.platform),
            "--interval-secs" => {
                cli.interval_secs = args.next().and_then(|v| v.parse().ok()).unwrap_or(cli.interval_secs)
            }
            "--once" => cli.once = true,
            "--draft-only" => cli.draft_only = true,
            "--ingest-mentions" => cli.ingest_mentions = true,
            "--support" => cli.support = true,
            "--editor-handles" => {
                cli.editor_handles = parse_editor_handles(&args.next().unwrap_or_default())
            }
            "--no-likes-ingest" => cli.likes_ingest = false,
            _ => {}
        }
    }
    cli
}

/// The afferent read query for a platform's handle:
/// - `x` → mentions of, and replies to, our handle.
/// - `huggingface` → the org name itself (org activity is "addressed to us").
fn read_query(platform: &str, handle: &str) -> String {
    match platform {
        "huggingface" => handle.to_string(),
        _ => format!("@{handle} OR to:{handle}"),
    }
}

/// POST a read action to `/api/social`; return perceived posts plus the remaining
/// edgework rate budget (from `X-RateLimit-Remaining`). Platform-aware:
/// - `x` (and others) → `action:"search"` over a mentions query.
/// - `huggingface` → `action:"org-models"` over the org (its new releases). The
///   org's own activity is, by construction, "addressed to us" → mark `mention`.
fn read_mentions(
    http: &ureq::Agent,
    cli: &Cli,
    key: &str,
) -> Result<(Vec<PerceivedPost>, u32), String> {
    let url = format!("{}/api/social", cli.dashrelay_url.trim_end_matches('/'));
    let handle = read_query(&cli.platform, &cli.handle);
    let body = if cli.platform == "huggingface" {
        // Thoth oversees the org by perceiving its new model releases (afferent).
        // Reads are public — no token needed on the dashrelay side.
        serde_json::json!({
            "platform": "huggingface",
            "action": "org-models",
            "orgName": handle,
            "sort": "createdAt",
            "limit": 20,
        })
    } else {
        serde_json::json!({
            "platform": cli.platform,
            "action": "search",
            "query": handle,
        })
    };
    let resp = http
        .post(&url)
        .set("Authorization", &format!("Bearer {key}"))
        .set("Content-Type", "application/json")
        .send_json(body)
        .map_err(|e| format!("read /api/social: {e}"))?;
    let rate_remaining = rate_remaining_from_header(resp.header("X-RateLimit-Remaining"));
    let value: serde_json::Value = resp.into_json().map_err(|e| e.to_string())?;
    let mut posts: Vec<PerceivedPost> = serde_json::from_value(value["posts"].clone()).unwrap_or_default();
    for p in &mut posts {
        p.mention = true;
    }
    Ok((posts, rate_remaining))
}

/// POST the gated utterance action to `/api/social`.
fn post_utterance(http: &ureq::Agent, cli: &Cli, key: &str, action_json: &str) -> Result<(), String> {
    let url = format!("{}/api/social", cli.dashrelay_url.trim_end_matches('/'));
    http.post(&url)
        .set("Authorization", &format!("Bearer {key}"))
        .set("Content-Type", "application/json")
        .send_string(action_json)
        .map(|_| ())
        .map_err(|e| format!("post /api/social: {e}"))
}

fn safe_item_id_segment(input: &str) -> String {
    input
        .chars()
        .map(|ch| {
            if ch.is_ascii_alphanumeric() || ch == '-' || ch == '_' || ch == '.' {
                ch
            } else {
                '_'
            }
        })
        .take(96)
        .collect()
}

fn post_author(post: &PerceivedPost) -> String {
    let author = post
        .author_username
        .as_deref()
        .filter(|s| !s.trim().is_empty())
        .unwrap_or_else(|| post.author_id.trim());
    let normalized = author.trim_start_matches('@');
    if normalized.is_empty() {
        "unknown".to_string()
    } else {
        normalized.to_string()
    }
}

fn mention_post_url(post: &PerceivedPost) -> Option<String> {
    let id = post.id.trim();
    if id.is_empty() {
        return None;
    }
    match post.platform.as_str() {
        "x" | "twitter" => {
            let author = post_author(post);
            if author.is_empty() || author == "unknown" {
                None
            } else {
                Some(format!("https://x.com/{author}/status/{id}"))
            }
        }
        "huggingface" => Some(format!("https://huggingface.co/{id}")),
        _ => None,
    }
}

/// The replied-to (or quoted) post a mention points at — usually the actual
/// news item when the editor replies to a story tagging the broadcast handle.
#[derive(Debug, Clone, PartialEq, Eq)]
struct ParentPost {
    id: String,
    author: String,
    text: String,
}

/// Resolve the parent of an X mention through dashrelay `x:lookup` (bearer
/// read). Graceful: any failure returns None and the mention rides alone.
fn lookup_parent(http: &ureq::Agent, cli: &Cli, key: &str, post_id: &str) -> Option<ParentPost> {
    if post_id.trim().is_empty() {
        return None;
    }
    let url = format!("{}/api/social", cli.dashrelay_url.trim_end_matches('/'));
    let resp = http
        .post(&url)
        .set("Authorization", &format!("Bearer {key}"))
        .set("Content-Type", "application/json")
        .send_json(serde_json::json!({ "platform": "x", "action": "lookup", "id": post_id }))
        .ok()?;
    let value: serde_json::Value = resp.into_json().ok()?;
    let parent = value.get("parent")?;
    let id = parent["id"].as_str()?.trim().to_string();
    let text = parent["text"].as_str()?.trim().to_string();
    if id.is_empty() || text.is_empty() {
        return None;
    }
    let author = parent["authorUsername"]
        .as_str()
        .map(|a| a.trim_start_matches('@').to_string())
        .filter(|a| !a.is_empty())
        .unwrap_or_else(|| "unknown".to_string());
    Some(ParentPost { id, author, text })
}

fn mention_content_item(
    post: &PerceivedPost,
    observed_at_ms: u64,
    parent: Option<&ParentPost>,
    is_editor: bool,
) -> Option<serde_json::Value> {
    let id = post.id.trim();
    let text = post.text.trim();
    if id.is_empty() || text.is_empty() {
        return None;
    }
    let platform = if post.platform.trim().is_empty() {
        "x"
    } else {
        post.platform.trim()
    };
    let author = post_author(post);
    let support_request = triage_mention(post);
    let source = if support_request.is_some() {
        "thoth-support-mention"
    } else if parent.is_some() && !is_editor {
        // A non-editor flagged a post: it rides as an unvetted public tip so
        // every downstream surface can see it carried no editorial weight.
        "thoth-public-tip"
    } else {
        "thoth-read-mentions"
    };
    let item_id = format!(
        "thoth-mention:{}:{}",
        safe_item_id_segment(platform),
        safe_item_id_segment(id)
    );
    let title = match (&support_request, parent) {
        (Some(req), _) => format!("Support mention from @{} on {}", req.requester, platform),
        (None, Some(p)) if is_editor => {
            format!("Flagged by @{}: post by @{} on {}", author, p.author, platform)
        }
        (None, Some(p)) => format!("Public tip via @{}: post by @{} on {}", author, p.author, platform),
        (None, None) => format!("Mention from @{} on {}", author, platform),
    };
    // The flagger's commentary is the reply minus the @-handle plumbing; a bare
    // pointer reply contributes provenance, not body copy.
    let commentary = parent.map(|_| {
        text.split_whitespace()
            .filter(|w| !w.starts_with('@'))
            .collect::<Vec<_>>()
            .join(" ")
    });
    let body = match (&support_request, parent, commentary.as_deref()) {
        (Some(req), _, _) => format!(
            "@{} asked publicly on {}: \"{}\"\n\nOriginal mention: {}",
            req.requester, platform, req.question, text
        ),
        // The mention is a pointer; the parent is the story. Lead with it.
        // Editors lend the desk's weight; everyone else is an unvetted tip.
        (None, Some(p), Some("")) | (None, Some(p), None) if is_editor => format!(
            "Post by @{} on {}, flagged by editor @{}: {}",
            p.author, platform, author, p.text
        ),
        (None, Some(p), Some(note)) if is_editor => format!(
            "Post by @{} on {}, flagged by @{}: {}\n\nEditor's note from @{}: {}",
            p.author, platform, author, p.text, author, note
        ),
        (None, Some(p), Some("")) | (None, Some(p), None) => format!(
            "Post by @{} on {} (public tip via @{}, an unvetted account — no editorial weight): {}",
            p.author, platform, author, p.text
        ),
        (None, Some(p), Some(note)) => format!(
            "Post by @{} on {} (public tip via @{}, an unvetted account — no editorial weight): {}\n\nTipster's note from @{}: {}",
            p.author, platform, author, p.text, author, note
        ),
        (None, None, _) => format!("@{} on {}: {}", author, platform, text),
    };
    let mut item = serde_json::json!({
        "itemId": item_id,
        "source": source,
        "kind": "post",
        "title": title,
        "body": body,
        "observedAt": observed_at_ms,
    });
    // Point the item at the story (the parent) when there is one; the bare
    // mention url otherwise.
    let url = match (parent, post.platform.as_str()) {
        (Some(p), "x") | (Some(p), "twitter") if p.author != "unknown" => {
            Some(format!("https://x.com/{}/status/{}", p.author, p.id))
        }
        _ => mention_post_url(post),
    };
    if let Some(url) = url {
        item["url"] = serde_json::Value::String(url);
    }
    Some(item)
}

/// The tweet a liked post quotes — when an editor likes a quote-tweet, the
/// quoted post is the real source, not the quoter's caption.
#[derive(Debug, Clone, PartialEq, Eq)]
struct QuotedPost {
    id: String,
    author: String,
    text: String,
}

/// A liked tweet (a silent editorial flag — the editor liked it, no public
/// mention required).
#[derive(Debug, Clone, PartialEq, Eq)]
struct LikedPost {
    id: String,
    author: String,
    text: String,
    created_at_ms: Option<u64>,
    /// Present when the liked tweet is itself a quote-tweet.
    quoted: Option<QuotedPost>,
}

/// Only likes of reasonably fresh tweets become flags — an old like isn't news.
const LIKE_FLAG_MAX_AGE_MS: u64 = 72 * 60 * 60 * 1000;

/// Fetch an editor's recent likes through dashrelay `x:likes` (the editor's own
/// OAuth2 user token via fractal-iam — likes are private on X). Graceful: any
/// failure returns the error string for logging; the tick continues.
fn editor_likes(
    http: &ureq::Agent,
    cli: &Cli,
    key: &str,
    handle: &str,
) -> Result<Vec<LikedPost>, String> {
    let url = format!("{}/api/social", cli.dashrelay_url.trim_end_matches('/'));
    let resp = http
        .post(&url)
        .set("Authorization", &format!("Bearer {key}"))
        .set("Content-Type", "application/json")
        .send_json(serde_json::json!({
            "platform": "x",
            "action": "likes",
            "username": handle,
            "maxResults": 10,
        }))
        .map_err(|e| format!("likes /api/social (@{handle}): {e}"))?;
    let value: serde_json::Value = resp.into_json().map_err(|e| e.to_string())?;
    if let Some(err) = value["error"].as_str() {
        return Err(format!("@{handle}: {err}"));
    }
    let posts = value["posts"].as_array().cloned().unwrap_or_default();
    Ok(posts
        .iter()
        .filter_map(|p| {
            let id = p["id"].as_str()?.trim().to_string();
            let text = p["text"].as_str()?.trim().to_string();
            if id.is_empty() || text.is_empty() {
                return None;
            }
            let author = p["authorUsername"]
                .as_str()
                .map(|a| a.trim_start_matches('@').to_string())
                .filter(|a| !a.is_empty())
                .unwrap_or_else(|| "unknown".to_string());
            let quoted = p.get("quoted").and_then(|q| {
                let qid = q["id"].as_str()?.trim().to_string();
                let qtext = q["text"].as_str()?.trim().to_string();
                if qid.is_empty() || qtext.is_empty() {
                    return None;
                }
                let qauthor = q["authorUsername"]
                    .as_str()
                    .map(|a| a.trim_start_matches('@').to_string())
                    .filter(|a| !a.is_empty())
                    .unwrap_or_else(|| "unknown".to_string());
                Some(QuotedPost { id: qid, author: qauthor, text: qtext })
            });
            Some(LikedPost {
                id,
                author,
                text,
                created_at_ms: p["createdAtMs"].as_u64(),
                quoted,
            })
        })
        .collect())
}

/// The protocol69 content item body cap is 4096 BYTES; leave headroom so the
/// offer never bounces on an unwrapped thread.
const THREAD_BODY_MAX_BYTES: usize = 3800;

/// Cap the unwrapped thread by whole posts, not a mid-tweet byte cut: a thread's
/// thesis lands in its opening posts, and an over-long body destabilizes the
/// judge. Keep the lede; summarize the tail as a count.
const THREAD_MAX_POSTS: usize = 12;

/// Unwrap an author's self-thread through dashrelay `x:thread`. Returns the
/// ordered tweet texts when the liked tweet is part of one (count > 1).
/// Graceful: any failure returns None and the like rides as a single post.
fn fetch_thread_texts(
    http: &ureq::Agent,
    cli: &Cli,
    key: &str,
    tweet_id: &str,
) -> Option<Vec<String>> {
    let url = format!("{}/api/social", cli.dashrelay_url.trim_end_matches('/'));
    let resp = http
        .post(&url)
        .set("Authorization", &format!("Bearer {key}"))
        .set("Content-Type", "application/json")
        .send_json(serde_json::json!({ "platform": "x", "action": "thread", "id": tweet_id }))
        .ok()?;
    let value: serde_json::Value = resp.into_json().ok()?;
    let tweets = value["tweets"].as_array()?;
    if tweets.len() < 2 {
        return None; // a lone tweet is not a thread — no pattern, no unwrap
    }
    Some(
        tweets
            .iter()
            .filter_map(|t| t["text"].as_str().map(|s| s.trim().to_string()))
            .filter(|s| !s.is_empty())
            .collect(),
    )
}

/// Join an unwrapped thread into one body: the lede posts in order, the tail
/// noted as a count. Capped by post-count first (keeps the thesis whole and the
/// judge prompt sane), then a byte backstop at a char boundary.
fn compose_thread_body(author: &str, editor: &str, texts: &[String]) -> String {
    let total = texts.len();
    let kept = texts.len().min(THREAD_MAX_POSTS);
    let mut body = format!(
        "Thread by @{author} on x ({total} posts), liked by editor @{editor}:"
    );
    for (i, text) in texts.iter().take(kept).enumerate() {
        body.push_str(&format!("\n\n[{}] {}", i + 1, text));
    }
    if total > kept {
        body.push_str(&format!("\n\n[+{} more posts in thread]", total - kept));
    }
    if body.len() > THREAD_BODY_MAX_BYTES {
        let mut cut = THREAD_BODY_MAX_BYTES;
        while !body.is_char_boundary(cut) {
            cut -= 1;
        }
        body.truncate(cut);
        body.push_str("\n\n[thread truncated]");
    }
    body
}

/// Compose the contentTask item for an editor-liked post. None when the like
/// shouldn't flag: stale tweets, our own posts (no self-promotion loop), or
/// posts by the editors themselves.
fn like_content_item(
    post: &LikedPost,
    editor: &str,
    own_handle: &str,
    editor_handles: &[String],
    observed_at_ms: u64,
    thread_texts: Option<&[String]>,
) -> Option<serde_json::Value> {
    let author_lc = post.author.to_ascii_lowercase();
    if author_lc == "unknown"
        || author_lc == own_handle.to_ascii_lowercase()
        || editor_handles.contains(&author_lc)
    {
        return None;
    }
    match post.created_at_ms {
        Some(created) if observed_at_ms.saturating_sub(created) <= LIKE_FLAG_MAX_AGE_MS => {}
        _ => return None, // stale or unknown age — an old like isn't news
    }
    // Source precedence:
    // 1. QUOTE-tweet — the quoted post is the real source; the quoter's caption
    //    is a note. Cite/amplify the quoted original, not the quoter.
    // 2. Self-THREAD — unwrap so the judge reads the whole argument.
    // 3. A plain liked post.
    let (title, body, source_author, source_id) = match (&post.quoted, thread_texts.filter(|t| t.len() > 1)) {
        (Some(q), _) => {
            // The quoter's caption minus @-plumbing; often empty (a bare RT).
            let caption: String = post
                .text
                .split_whitespace()
                .filter(|w| !w.starts_with('@') && !w.contains("://"))
                .collect::<Vec<_>>()
                .join(" ");
            let body = if caption.trim().is_empty() {
                format!(
                    "Post by @{} on x, liked by editor @{} (quoted by @{}): {}",
                    q.author, editor, post.author, q.text
                )
            } else {
                format!(
                    "Post by @{} on x, liked by editor @{}: {}\n\nQuoted by @{} with: {}",
                    q.author, editor, q.text, post.author, caption
                )
            };
            (
                format!("Liked by @{}: post by @{} on x (quoted by @{})", editor, q.author, post.author),
                body,
                q.author.clone(),
                q.id.clone(),
            )
        }
        (None, Some(texts)) => (
            format!(
                "Liked by @{}: thread by @{} on x ({} posts)",
                editor,
                post.author,
                texts.len()
            ),
            compose_thread_body(&post.author, editor, texts),
            post.author.clone(),
            post.id.clone(),
        ),
        (None, None) => (
            format!("Liked by @{}: post by @{} on x", editor, post.author),
            format!(
                "Post by @{} on x, liked by editor @{}: {}",
                post.author, editor, post.text
            ),
            post.author.clone(),
            post.id.clone(),
        ),
    };
    Some(serde_json::json!({
        // Key on the liked tweet so re-likes dedupe; the body/url point at source.
        "itemId": format!("thoth-like:x:{}", safe_item_id_segment(&post.id)),
        "source": "thoth-editor-like",
        "kind": "post",
        "title": title,
        "body": body,
        "url": format!("https://x.com/{}/status/{}", source_author, source_id),
        "observedAt": observed_at_ms,
    }))
}

fn content_task_offer(item: &serde_json::Value) -> serde_json::Value {
    let item_id = item["itemId"].as_str().unwrap_or_default();
    let tokens: Vec<u8> = item_id.as_bytes().to_vec();
    serde_json::json!({
        "tokens": tokens,
        "workflowLambda": {
            "schemaVersion": "gnosis.protocol69.polyglot-lambda.v1",
            "language": "json",
            "entrypoint": "contentTask",
            "arguments": { "item": item },
        },
    })
}

fn offer_content_item(
    http: &ureq::Agent,
    cli: &Cli,
    item: &serde_json::Value,
) -> Result<String, String> {
    let url = format!("{}/protocol69/cache-miss/offer", cli.content_bus_url.trim_end_matches('/'));
    let body = content_task_offer(item);
    let mut req = http
        .post(&url)
        .set("Content-Type", "application/json");
    if let Some(token) = cli.content_bus_token.as_deref() {
        req = req.set("Authorization", &format!("Bearer {token}"));
    }
    let resp = req
        .send_json(body)
        .map_err(|e| format!("content bus offer: {e}"))?;
    let value: serde_json::Value = resp.into_json().map_err(|e| e.to_string())?;
    let status = value["status"]
        .as_str()
        .or_else(|| value["error"].as_str())
        .unwrap_or("unknown");
    Ok(status.to_string())
}

/// Build the efferent `/api/social` action JSON for an utterance, platform-aware.
///
/// - For most platforms this is the shared `{platform, action:"post", text, replyTo}`
///   shape (`utterance_action_json`) — the loop is unchanged.
/// - For `huggingface`, Thoth oversees by opening/commenting on a repo discussion.
///   `reply_to` carries the perceived post id: a model id (`org/repo`, opens a new
///   discussion) or a discussion id (`org/repo#num`, comments on it). Without a
///   target we cannot address a repo, so fall back to the shared shape (the
///   handler will reject an unknown HF post action, surfacing as a held error).
fn efferent_action_json(u: &SocialUtterance) -> String {
    if u.platform != "huggingface" {
        return utterance_action_json(u);
    }
    match u.reply_to.as_deref() {
        Some(target) if target.contains('#') => {
            let (repo, num) = target.split_once('#').unwrap_or((target, ""));
            let num: u64 = num.parse().unwrap_or(0);
            serde_json::json!({
                "platform": "huggingface",
                "action": "comment",
                "repoId": repo,
                "num": num,
                "text": u.text,
            })
            .to_string()
        }
        Some(repo) => serde_json::json!({
            "platform": "huggingface",
            "action": "open-discussion",
            "repoId": repo,
            "title": "Thoth",
            "description": u.text,
        })
        .to_string(),
        None => utterance_action_json(u),
    }
}

/// Ask Thoth's LM (openai-server, OpenAI-compatible) to compose the utterance.
fn generate_utterance(http: &ureq::Agent, openai_url: &str, prompt: &str) -> Result<String, String> {
    let url = format!("{}/v1/chat/completions", openai_url.trim_end_matches('/'));
    let body = serde_json::json!({
        "model": "thoth",
        "messages": [{ "role": "user", "content": prompt }],
        "max_tokens": 120,
    });
    let resp = http
        .post(&url)
        .set("Content-Type", "application/json")
        .send_json(body)
        .map_err(|e| format!("openai chat: {e}"))?;
    let value: serde_json::Value = resp.into_json().map_err(|e| e.to_string())?;
    let text = value["choices"][0]["message"]["content"]
        .as_str()
        .unwrap_or_default()
        .trim()
        .to_string();
    Ok(text)
}

/// Read the acoustic environment from the mesh (simulated/stub for now).
fn read_acoustic_environment() -> Result<Vec<String>, String> {
    // TK: actually read from the acoustic mesh or local mic.
    // For now, return an empty acoustic consensus.
    Ok(vec![])
}

/// One perceive → drive → reason → gate → speak iteration. Returns a human report.
fn tick(http: &ureq::Agent, cli: &Cli, key: Option<&str>) -> Result<String, String> {
    let Some(key) = key else {
        return Ok("no credential (THOTH_SOCIAL_DR_KEY unset) — idling, no posts".into());
    };
    if cli.handle.is_empty() {
        return Ok("no --handle / THOTH_SOCIAL_HANDLE — cannot perceive mentions, idling".into());
    }

    // 1. Perceive (afferent) + learn the remaining edgework budget.
    let (posts, rate_remaining) = read_mentions(http, cli, key)?;
    let acoustic_consensus = read_acoustic_environment().unwrap_or_default();
    
    let metrics = summarize(&cli.platform, &posts);
    let _frame = perceive(format!("thoth:social:{}", cli.platform), &cli.platform, &posts);

    // Respect the edgework budget before spending an LM call + post.
    if rate_remaining == 0 {
        return Ok(format!(
            "perceived {} posts; held: edgework-rate-exhausted (skipping reason+speak)",
            posts.len()
        ));
    }

    // 2. Drive — decide what (if anything) to do.
    let weights = DriveWeights::default();
    let (drive, reply_to) = match next_impulse(&metrics, &posts, &weights) {
        Impulse::Scan => {
            return Ok(format!("perceived {} posts; impulse=scan (quiet) — listening", posts.len()))
        }
        Impulse::Speak { drive, reply_to } => (drive, reply_to),
    };

    // 3. Reason — ask the LM for a candidate utterance.
    let mut prompt = build_utterance_prompt(drive, &posts, reply_to.as_deref());
    if !acoustic_consensus.is_empty() {
        prompt.push_str("\n\nAcoustic Environment Consensus:\n");
        for sound in &acoustic_consensus {
            prompt.push_str(&format!("- {sound}\n"));
        }
    }
    let text = generate_utterance(http, &cli.openai_url, &prompt)?;

    // 4. Gate (conscience) + 5. Speak (efferent).
    let gate = assemble_conscience(&text, rate_remaining);
    let autonomy = if cli.draft_only { Autonomy::DraftOnly } else { Autonomy::GatedAutonomous };
    let utterance = SocialUtterance { platform: cli.platform.clone(), text, reply_to };
    match propose_utterance(utterance, gate, autonomy) {
        MouthDecision::Speak(u) | MouthDecision::SpeakCautiously(u) => {
            let action = efferent_action_json(&u);
            post_utterance(http, cli, key, &action)?;
            Ok(format!("spoke [{drive:?}]: {}", u.text.replace('\n', " ")))
        }
        MouthDecision::Draft(u) => Ok(format!("drafted [{drive:?}] for review: {}", u.text.replace('\n', " "))),
        MouthDecision::Silent { reason } => Ok(format!("held [{drive:?}]: {reason}")),
    }
}

/// Support-desk iteration: triage support mentions and answer each through the
/// conscience gate (gated-autonomous), threading the reply under the question.
fn support_tick(http: &ureq::Agent, cli: &Cli, key: Option<&str>) -> Result<String, String> {
    let Some(key) = key else {
        return Ok("no credential (THOTH_SOCIAL_DR_KEY unset) — idling, no replies".into());
    };
    if cli.handle.is_empty() {
        return Ok("no --handle / THOTH_SOCIAL_HANDLE — cannot read support mentions, idling".into());
    }

    let (posts, rate_remaining) = read_mentions(http, cli, key)?;
    if rate_remaining == 0 {
        return Ok(format!("{} mentions; held: edgework-rate-exhausted", posts.len()));
    }
    let requests: Vec<_> = posts.iter().filter_map(triage_mention).collect();
    if requests.is_empty() {
        return Ok(format!("{} mentions; 0 support requests", posts.len()));
    }

    let autonomy = if cli.draft_only { Autonomy::DraftOnly } else { Autonomy::GatedAutonomous };
    let total = requests.len();
    let (mut answered, mut drafted, mut held) = (0u32, 0u32, 0u32);
    for req in requests {
        // KB retrieval (docs grounding) is a future enhancement; None for now.
        let prompt = build_support_reply_prompt(&req, None);
        let text = match generate_utterance(http, &cli.openai_url, &prompt) {
            Ok(t) => t,
            Err(e) => {
                eprintln!("[thoth-social] support: LM error for {}: {e}", req.post_id);
                held += 1;
                continue;
            }
        };
        let gate = assemble_conscience(&text, rate_remaining);
        let utterance = SocialUtterance {
            platform: req.platform.clone(),
            text,
            reply_to: Some(req.post_id.clone()), // thread under the question
        };
        match propose_utterance(utterance, gate, autonomy) {
            MouthDecision::Speak(u) | MouthDecision::SpeakCautiously(u) => {
                post_utterance(http, cli, key, &efferent_action_json(&u))?;
                answered += 1;
            }
            MouthDecision::Draft(_) => drafted += 1,
            MouthDecision::Silent { reason } => {
                eprintln!("[thoth-social] support: held {} ({reason})", req.post_id);
                held += 1;
            }
        }
    }
    Ok(format!("support: {total} requests — {answered} answered, {drafted} drafted, {held} held"))
}

/// Content-bus source iteration: read mentions through the same afferent lens,
/// emit each stable mention as a contentTask, and let the Thoth content judge
/// decide `air | post | air+post | spike` downstream.
fn content_bus_mentions_tick(http: &ureq::Agent, cli: &Cli, key: Option<&str>) -> Result<String, String> {
    let Some(key) = key else {
        return Ok("no credential (THOTH_SOCIAL_DR_KEY unset) — idling, no content offers".into());
    };
    if cli.handle.is_empty() {
        return Ok("no --handle / THOTH_SOCIAL_HANDLE — cannot read mentions, idling".into());
    }

    let (posts, rate_remaining) = read_mentions(http, cli, key)?;
    if rate_remaining == 0 {
        return Ok(format!("{} mentions; held: edgework-rate-exhausted", posts.len()));
    }
    let observed_at = unix_time_millis();
    let (mut offered, mut filled, mut skipped, mut rejected) = (0u32, 0u32, 0u32, 0u32);
    for post in &posts {
        // A reply-mention is a pointer at its parent — resolve the story it flags.
        let parent = if post.platform == "x" || post.platform == "twitter" {
            lookup_parent(http, cli, key, post.id.trim())
        } else {
            None
        };
        let is_editor = cli
            .editor_handles
            .contains(&post_author(post).to_ascii_lowercase());
        let Some(item) = mention_content_item(post, observed_at, parent.as_ref(), is_editor)
        else {
            skipped += 1;
            continue;
        };
        match offer_content_item(http, cli, &item) {
            Ok(status) if status == "pending" || status == "completed" => offered += 1,
            Ok(status) if status == "filled" => filled += 1,
            Ok(status) => {
                eprintln!(
                    "[thoth-social] content bus rejected {} ({status})",
                    item["itemId"].as_str().unwrap_or("<unknown>")
                );
                rejected += 1;
            }
            Err(e) => {
                eprintln!("[thoth-social] content bus offer error: {e}");
                rejected += 1;
            }
        }
    }
    // The editors' likes are silent flags — same bus, no public mention needed.
    let mut likes_report = String::new();
    if cli.likes_ingest {
        let (mut l_offered, mut l_dup, mut l_skipped, mut l_err) = (0u32, 0u32, 0u32, 0u32);
        for editor in &cli.editor_handles {
            let likes = match editor_likes(http, cli, key, editor) {
                Ok(likes) => likes,
                Err(e) => {
                    eprintln!("[thoth-social] likes read failed ({e}) — skipping @{editor}");
                    l_err += 1;
                    continue;
                }
            };
            for liked in &likes {
                // Gates first (fresh, not-own); only then pay the thread fetch.
                if like_content_item(liked, editor, &cli.handle, &cli.editor_handles, observed_at, None)
                    .is_none()
                {
                    l_skipped += 1;
                    continue;
                }
                let thread = fetch_thread_texts(http, cli, key, &liked.id);
                let Some(item) = like_content_item(
                    liked,
                    editor,
                    &cli.handle,
                    &cli.editor_handles,
                    observed_at,
                    thread.as_deref(),
                ) else {
                    l_skipped += 1;
                    continue;
                };
                match offer_content_item(http, cli, &item) {
                    Ok(status) if status == "pending" || status == "completed" => l_offered += 1,
                    Ok(status) if status == "filled" => l_dup += 1,
                    Ok(_) | Err(_) => l_dup += 1, // re-offers of judged items land here
                }
            }
        }
        likes_report = format!(
            "; editor likes — {l_offered} offered, {l_dup} already filled, {l_skipped} skipped (stale/own), {l_err} editors unreadable"
        );
    }
    Ok(format!(
        "content-bus mentions: {} read — {offered} offered, {filled} already filled, {skipped} skipped, {rejected} rejected{likes_report}",
        posts.len()
    ))
}

fn unix_time_millis() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .unwrap_or_default()
        .as_millis() as u64
}

fn main() {
    let cli = parse_cli();
    let key = std::env::var("THOTH_SOCIAL_DR_KEY").ok().filter(|k| !k.is_empty());
    let http = ureq::AgentBuilder::new()
        .timeout_connect(Duration::from_secs(3))
        .timeout_read(Duration::from_secs(60))
        .timeout_write(Duration::from_secs(10))
        .build();

    eprintln!(
        "[thoth-social] starting (platform={}, handle={}, once={}, draft_only={}, ingest_mentions={}, credential={})",
        cli.platform,
        if cli.handle.is_empty() { "<none>" } else { &cli.handle },
        cli.once,
        cli.draft_only,
        cli.ingest_mentions,
        if key.is_some() { "present" } else { "absent" },
    );

    loop {
        let result = if cli.ingest_mentions {
            content_bus_mentions_tick(&http, &cli, key.as_deref())
        } else if cli.support {
            support_tick(&http, &cli, key.as_deref())
        } else {
            tick(&http, &cli, key.as_deref())
        };
        match result {
            Ok(report) => eprintln!("[thoth-social] {report}"),
            Err(e) => eprintln!("[thoth-social] error: {e}"),
        }
        if cli.once {
            break;
        }
        std::thread::sleep(Duration::from_secs(cli.interval_secs));
    }
}

