    #[test]
    fn editor_likes_become_weighted_flags_with_guards() {
        let editors = vec!["cissypatterson".to_string(), "taylorbuley".to_string()];
        let now: u64 = 1_770_000_000_000;
        let fresh = LikedPost {
            id: "3000000000000000001".into(),
            author: "newsdesk".into(),
            text: "Reservoir levels hit a 30-year low.".into(),
            created_at_ms: Some(now - 60_000),
            quoted: None,
        };
        let item = like_content_item(&fresh, "taylorbuley", "forkracefold", &editors, now, None)
            .expect("fresh editor like becomes an item");
        assert_eq!(item["itemId"], "thoth-like:x:3000000000000000001");
        assert_eq!(item["source"], "thoth-editor-like");
        assert!(item["body"].as_str().unwrap().contains("liked by editor @taylorbuley"));
        assert_eq!(item["url"], "https://x.com/newsdesk/status/3000000000000000001");

        // Stale tweets, our own posts, and editor-authored posts never flag.
        let stale = LikedPost { created_at_ms: Some(now - LIKE_FLAG_MAX_AGE_MS - 1), ..fresh.clone() };
        assert!(like_content_item(&stale, "taylorbuley", "forkracefold", &editors, now, None).is_none());
        let unknown_age = LikedPost { created_at_ms: None, ..fresh.clone() };
        assert!(like_content_item(&unknown_age, "taylorbuley", "forkracefold", &editors, now, None).is_none());
        let own = LikedPost { author: "forkracefold".into(), ..fresh.clone() };
        assert!(like_content_item(&own, "taylorbuley", "forkracefold", &editors, now, None).is_none());
        let self_like = LikedPost { author: "CissyPatterson".into(), ..fresh };
        assert!(like_content_item(&self_like, "taylorbuley", "forkracefold", &editors, now, None).is_none());
    }

    #[test]
    fn liked_quote_tweet_treats_the_quoted_post_as_the_source() {
        let editors = vec!["taylorbuley".to_string()];
        let now: u64 = 1_770_000_000_000;
        let quoting = LikedPost {
            id: "5000000000000000009".into(),
            author: "pundit".into(),
            text: "@pundit this is exactly right".into(),
            created_at_ms: Some(now - 60_000),
            quoted: Some(QuotedPost {
                id: "5000000000000000001".into(),
                author: "centralbank".into(),
                text: "We are cutting the policy rate by 50 basis points effective Monday.".into(),
            }),
        };
        let item = like_content_item(&quoting, "taylorbuley", "forkracefold", &editors, now, None)
            .expect("liked quote-tweet becomes an item");
        // Item keys on the liked tweet for dedupe...
        assert_eq!(item["itemId"], "thoth-like:x:5000000000000000009");
        // ...but body, url, and title point at the QUOTED source.
        let body = item["body"].as_str().unwrap();
        assert!(body.contains("Post by @centralbank on x"));
        assert!(body.contains("50 basis points"));
        assert!(body.contains("Quoted by @pundit with: this is exactly right"));
        assert_eq!(item["url"], "https://x.com/centralbank/status/5000000000000000001");
        assert!(item["title"].as_str().unwrap().contains("post by @centralbank on x (quoted by @pundit)"));

        // A bare quote (no caption) still leads with the quoted source.
        let bare = LikedPost { text: "@pundit".into(), ..quoting };
        let bare_item = like_content_item(&bare, "taylorbuley", "forkracefold", &editors, now, None).unwrap();
        let bare_body = bare_item["body"].as_str().unwrap();
        assert!(bare_body.contains("quoted by @pundit"));
        assert!(!bare_body.contains("Quoted by @pundit with:"));
    }

    #[test]
    fn liked_thread_unwraps_in_order_and_caps_under_the_byte_budget() {
        let editors = vec!["taylorbuley".to_string()];
        let now: u64 = 1_770_000_000_000;
        let seed = LikedPost {
            id: "4000000000000000003".into(),
            author: "ido".into(),
            text: "(3/15) the middle of the argument".into(),
            created_at_ms: Some(now - 60_000),
            quoted: None,
        };
        let texts: Vec<String> = vec![
            "(1/15) the opener".into(),
            "(2/15) the setup".into(),
            "(3/15) the middle of the argument".into(),
        ];
        let item = like_content_item(&seed, "taylorbuley", "forkracefold", &editors, now, Some(&texts))
            .expect("liked thread becomes an item");
        let body = item["body"].as_str().unwrap();
        assert!(body.starts_with("Thread by @ido on x (3 posts), liked by editor @taylorbuley:"));
        assert!(body.contains("[1] (1/15) the opener"));
        assert!(body.contains("[3] (3/15) the middle"));
        assert!(item["title"].as_str().unwrap().contains("thread by @ido on x (3 posts)"));

        // A single-text "thread" is not a thread — plain like composition.
        let single: Vec<String> = vec!["just one".into()];
        let plain = like_content_item(&seed, "taylorbuley", "forkracefold", &editors, now, Some(&single))
            .expect("single text rides as plain like");
        assert!(plain["body"].as_str().unwrap().starts_with("Post by @ido on x, liked by editor"));

        // A long thread caps by post count and notes the omitted tail.
        let big: Vec<String> = (0..40).map(|i| format!("post number {i}")).collect();
        let capped = compose_thread_body("ido", "taylorbuley", &big);
        assert!(capped.contains("Thread by @ido on x (40 posts)"));
        assert!(capped.contains(&format!("[+{} more posts in thread]", 40 - THREAD_MAX_POSTS)));
        assert!(capped.contains(&format!("[{THREAD_MAX_POSTS}] post number {}", THREAD_MAX_POSTS - 1)));
        assert!(!capped.contains(&format!("[{}]", THREAD_MAX_POSTS + 1)));
        // Byte backstop still holds for pathologically long individual posts.
        let huge: Vec<String> = (0..5).map(|_| "z".repeat(2000)).collect();
        let clamped = compose_thread_body("ido", "taylorbuley", &huge);
        assert!(clamped.len() <= THREAD_BODY_MAX_BYTES + "\n\n[thread truncated]".len());
    }

